// Buffer API Configuration
const BUFFER_ACCESS_TOKEN = 'YOUR_BUFFER_ACCESS_TOKEN';
const BUFFER_CLIENT_ID = 'YOUR_BUFFER_CLIENT_ID';

// Get the current item data
const item = $input.item.json;

// Parse platforms from the sheet (comma-separated)
const platforms = item.Platforms ? item.Platforms.split(',').map(p => p.trim()) : [];

// Format content for each platform
const formatContent = (platform, content, link, hashtags) => {
  let formattedContent = content;

  // Platform-specific formatting
  switch(platform.toLowerCase()) {
    case 'twitter':
    case 'x':
      // Twitter has 280 character limit
      if (link) {
        const maxContentLength = 250 - (hashtags ? hashtags.length : 0);
        formattedContent = content.substring(0, maxContentLength) + '...';
      }
      formattedContent = `${formattedContent}${hashtags ? ' ' + hashtags : ''}${link ? ' ' + link : ''}`;
      return formattedContent.substring(0, 280);

    case 'facebook':
    case 'linkedin':
      formattedContent = content;
      if (hashtags) formattedContent += '\n\n' + hashtags;
      if (link) formattedContent += '\n\n' + link;
      return formattedContent;

    case 'instagram':
      // Instagram doesn't support clickable links in posts
      formattedContent = content;
      if (hashtags) formattedContent += '\n\n' + hashtags;
      return formattedContent;

    default:
      return content;
  }
};

// Create an array of posts for each platform
const posts = platforms.map(platform => ({
  platform: platform,
  content: formatContent(platform, item.Content, item.Link, item.Hashtags),
  mediaUrl: item.MediaURL || null,
  scheduledTime: item.ScheduledTime || null,
  rowId: $position + 2, // +2 for header row and 0-based index
  originalData: item
}));

return posts;

// Get the Buffer profiles from the previous node
const profiles = $('Get Buffer Profiles').first().json;
const post = $input.item.json;

// Map platform names to Buffer profile IDs
const platformMapping = {
  'twitter': 'twitter',
  'x': 'twitter',
  'facebook': 'facebook',
  'linkedin': 'linkedin',
  'instagram': 'instagram'
};

// Find the matching Buffer profile
const platformKey = platformMapping[post.platform.toLowerCase()];
const profile = profiles.find(p => p.service === platformKey);

if (!profile) {
  throw new Error(`No Buffer profile found for platform: ${post.platform}`);
}

// Return the post with the profile ID
return {
  ...post,
  profileId: profile.id,
  profileService: profile.service
};

