const now = new Date();
const in48h = new Date(Date.now() + 48 * 60 * 60 * 1000);

// Map rows: assuming range columns:
// A: row_id, B: status, C: scheduled_time, D: caption, E: image_url, F: video_url
const out = [];
for (const item of items) {
  const [row_id, status, scheduled_time, caption, image_url, video_url] = item.json;
  if (!row_id) continue; // must have row id for update
  if (String(status).toLowerCase() !== 'approved') continue;
  const dt = new Date(scheduled_time);
  if (isNaN(dt.getTime())) continue; // invalid date
  if (dt <= in48h && dt >= now) {
    // Build Buffer payload for both profiles from env vars
    const fbId = $env.68febc7e669affb4c9897505;
    const igId = $env.68febc4e669affb4c98974cd;
    const profile_ids = [fbId, igId].filter(Boolean);
    if (profile_ids.length < 2) {
      throw new Error('Missing Buffer profile IDs. Set FB_PAGE_PROFILE_ID and IG_PROFILE_PROFILE_ID environment variables.');
    }

    const media = {};
    if (image_url) media.photo = image_url;
    if (video_url) media.video = video_url;

    const payload = {
      text: caption || '',
      scheduled_at: dt.toISOString(),
      profile_ids,
      // Buffer expects media only if provided
      ...(Object.keys(media).length ? { media } : {})
    };

    out.push({
      json: {
        row_id,
        status,
        scheduled_time: dt.toISOString(),
        caption,
        image_url,
        video_url,
        buffer_payload: payload
      }
    });
  }
}
return out;

