// Hardcode your Buffer profile IDs (strings)
const FB_PAGE_PROFILE_ID = '68febc7e669affb4c9897505';
const IG_PROFILE_PROFILE_ID = '68febc4e669affb4c98974cd';

// Read fields from the current item
const row_id         = $json.row_id;
const status         = ($json.status || '').toLowerCase();
const scheduled_time = $json.scheduled_time;
const caption        = $json.caption || '';
const image_url      = $json.image_url || '';
const video_url      = $json.video_url || '';

// Only proceed for approved items; you can also filter earlier in the sheet query
if (status !== 'approved') {
  // Pass through unchanged (or return null to drop)
  return { ...$json, skipped: true, reason: 'not approved' };
}

// Validate date and convert to ISO
const dt = new Date(scheduled_time);
if (isNaN(dt.getTime())) {
  throw new Error(`Invalid scheduled_time for row ${row_id}: ${scheduled_time}`);
}

// Build media only when present
const media = {};
if (image_url) media.photo = image_url;
if (video_url) media.video = video_url;

const buffer_payload = {
  text: caption,
  scheduled_at: dt.toISOString(),
  // ALWAYS post to both platforms
  profile_ids: [FB_PAGE_PROFILE_ID, IG_PROFILE_PROFILE_ID],
  ...(Object.keys(media).length ? { media } : {})
};

// Return augmented item; the next node will read buffer_payload
return { ...$json, buffer_payload };
